/// Create FunctionTemplate for ShadowRoot.
pub fn create_shadow_root_template<'s>(
    scope: &v8::PinScope<'s, '_>,
    _parent: Option<v8::Local<'s, v8::FunctionTemplate>>,
) -> v8::Local<'s, v8::FunctionTemplate> {
    let tmpl = v8::FunctionTemplate::builder_raw(illegal_constructor).build(scope);
    tmpl.read_only_prototype();
    tmpl.set_class_name(v8::String::new(scope, "ShadowRoot").unwrap());
    if let Some(p) = _parent {
        tmpl.inherit(p);
    }

    let proto = tmpl.prototype_template(scope);
    {
        let tag_sym = v8::Symbol::get_to_string_tag(scope);
        let tag_val = v8::String::new(scope, "ShadowRoot").unwrap();
        proto.set(tag_sym.into(), tag_val.into());
    }
    install_shadow_root_members_1(scope, proto);
    install_shadow_root_members_2(scope, proto);

    tmpl
}

